// Keep only active competitors and normalize fields
const items = $input.all();
const active = items.filter(item => {
  const status = (item.json.status || '').toLowerCase().trim();
  return status === 'active';
});

if (active.length === 0) {
  throw new Error('No active competitors found. Add rows with status=active to the competitors sheet.');
}

return active.map(item => ({ json: {
  competitor_name: (item.json.competitor_name || '').trim(),
  url: (item.json.url || '').trim(),
  section_to_monitor: (item.json.section_to_monitor || '').trim(),
  last_content: item.json.last_content || '',
  last_checked: item.json.last_checked || '',
  status: 'active'
}}));

function simpleHash(str) {
  let h1 = 0xdeadbeef, h2 = 0x41c6ce57;
  for (let i = 0; i < str.length; i++) {
    const ch = str.charCodeAt(i);
    h1 = Math.imul(h1 ^ ch, 2654435761);
    h2 = Math.imul(h2 ^ ch, 1597334677);
  }
  h1 = Math.imul(h1 ^ (h1 >>> 16), 2246822507) ^ Math.imul(h2 ^ (h2 >>> 13), 3266489909);
  h2 = Math.imul(h2 ^ (h2 >>> 16), 2246822507) ^ Math.imul(h1 ^ (h1 >>> 13), 3266489909);
  return (4294967296 * (2097151 & h2) + (h1 >>> 0)).toString(16);
}

// Competitor metadata comes from the paired item in Filter Active
const competitor = $('Filter Active').item.json;

// HTTP response is the current item
const response = $input.item.json;

// Detect fetch failure: continueOnFail passes original item on error
// Real HTML will be in response.data or response.body (string, long)
const rawHtml = (typeof response.data === 'string' && response.data.length > 200)
  ? response.data
  : (typeof response.body === 'string' && response.body.length > 200)
  ? response.body
  : null;

if (!rawHtml) {
  return { json: {
    competitor_name: competitor.competitor_name,
    url: competitor.url,
    section_to_monitor: competitor.section_to_monitor,
    last_content: competitor.last_content,
    last_checked: competitor.last_checked,
    changeDetected: false,
    comparisonStatus: 'fetch_error',
    newContent: '',
    newHash: '',
    fetchedAt: new Date().toISOString(),
    error: 'Fetch failed — timeout, 403, or network error'
  }};
}

const priceMatches = (rawHtml.match(/\$[\s]?[\d.,]+/g) || []).slice(0, 10);
const titleMatches = (rawHtml.match(/<h[1-3][^>]*>([^<]+)<\/h[1-3]>/gi) || [])
  .map(h => h.replace(/<[^>]+>/g, '').trim())
  .filter(t => t.length > 2)
  .slice(0, 5);

const cleanText = rawHtml
  .replace(/<script[\s\S]*?<\/script>/gi, '')
  .replace(/<style[\s\S]*?<\/style>/gi, '')
  .replace(/<nav[\s\S]*?<\/nav>/gi, '')
  .replace(/<footer[\s\S]*?<\/footer>/gi, '')
  .replace(/<header[\s\S]*?<\/header>/gi, '')
  .replace(/<!--[\s\S]*?-->/g, '')
  .replace(/<[^>]+>/g, ' ')
  .replace(/&nbsp;/g, ' ').replace(/&amp;/g, '&').replace(/&lt;/g, '<').replace(/&gt;/g, '>')
  .replace(/\s+/g, ' ')
  .trim()
  .substring(0, 3000);

const newHash = simpleHash(cleanText);

// FIRST RUN: no baseline stored yet → save baseline, log as first_run
if (!competitor.last_content || competitor.last_content.trim() === '') {
  return { json: {
    competitor_name: competitor.competitor_name,
    url: competitor.url,
    section_to_monitor: competitor.section_to_monitor,
    last_content: competitor.last_content,
    last_checked: competitor.last_checked,
    changeDetected: true,
    comparisonStatus: 'baseline',
    newContent: cleanText,
    newHash,
    extractedPrices: priceMatches,
    extractedTitles: titleMatches,
    fetchedAt: new Date().toISOString(),
    // Pre-fill AI fields so no AI call needed on first run
    criticality: 'LOW',
    change_type: 'first_run',
    summary: 'Primera ejecución — línea base establecida para ' + competitor.competitor_name,
    business_impact: 'Sin impacto — solo se establece la línea base inicial',
    recommended_action: 'Ninguna acción necesaria',
    urgency: 'monitor',
    skipAI: true
  }};
}

// COMPARE: check if content changed
const oldHash = simpleHash(competitor.last_content);

if (oldHash === newHash) {
  // No change — end path here, no Sheets write needed
  return { json: {
    competitor_name: competitor.competitor_name,
    url: competitor.url,
    changeDetected: false,
    comparisonStatus: 'no_change',
    fetchedAt: new Date().toISOString()
  }};
}

// CHANGE DETECTED — build diff for AI
const oldSnippet = competitor.last_content.substring(0, 800);
const newSnippet = cleanText.substring(0, 800);
const oldWordSet = new Set(competitor.last_content.split(/\s+/).filter(w => w.length > 4));
const addedTerms = [...new Set(cleanText.split(/\s+/).filter(w => w.length > 4 && !oldWordSet.has(w)))].slice(0, 30);

const diff = `CONTENIDO ANTERIOR:\n${oldSnippet}\n\nCONTENIDO ACTUAL:\n${newSnippet}\n\nTÉRMINOS NUEVOS: ${addedTerms.join(', ') || 'ninguno'}\nPRECIOS: ${priceMatches.join(', ') || 'ninguno'}\nTÍTULOS: ${titleMatches.join(' | ') || 'ninguno'}`;

return { json: {
  competitor_name: competitor.competitor_name,
  url: competitor.url,
  section_to_monitor: competitor.section_to_monitor,
  last_content: competitor.last_content,
  last_checked: competitor.last_checked,
  changeDetected: true,
  comparisonStatus: 'changed',
  newContent: cleanText,
  newHash,
  diff,
  fetchedAt: new Date().toISOString(),
  skipAI: false
}};

