const input = $input.item.json;
const rawResponse = input.response || input.text || '{}';

const jsonMatch = rawResponse.match(/\{[\s\S]*\}/);
let analysis;
try {
  analysis = JSON.parse(jsonMatch ? jsonMatch[0] : rawResponse);
} catch(e) {
  analysis = {
    criticality: 'LOW',
    change_type: 'other',
    summary: 'No se pudo parsear el análisis — revisar manualmente.',
    business_impact: 'Desconocido',
    recommended_action: 'Revisar el sitio directamente',
    urgency: 'monitor'
  };
}

if (!['CRITICAL', 'MODERATE', 'LOW'].includes(analysis.criticality)) analysis.criticality = 'LOW';

return { json: {
  competitor_name: input.competitor_name,
  url: input.url,
  section_to_monitor: input.section_to_monitor,
  newContent: input.newContent,
  newHash: input.newHash,
  fetchedAt: input.fetchedAt,
  criticality: analysis.criticality,
  change_type: analysis.change_type || 'other',
  summary: analysis.summary || '',
  business_impact: analysis.business_impact || '',
  recommended_action: analysis.recommended_action || '',
  urgency: analysis.urgency || 'monitor'
}};

// First-run baseline: no AI needed, just pass through with LOW criticality
const input = $input.item.json;
return { json: {
  competitor_name: input.competitor_name,
  url: input.url,
  section_to_monitor: input.section_to_monitor,
  newContent: input.newContent,
  newHash: input.newHash,
  fetchedAt: input.fetchedAt,
  criticality: 'LOW',
  change_type: 'first_run',
  summary: input.summary,
  business_impact: input.business_impact,
  recommended_action: input.recommended_action,
  urgency: 'monitor'
}};

const allRows = $input.all().map(item => item.json);
const oneWeekAgo = new Date();
oneWeekAgo.setDate(oneWeekAgo.getDate() - 7);

const weekChanges = allRows.filter(row => {
  if (!row.date) return false;
  try { return new Date(row.date) >= oneWeekAgo; } catch(e) { return false; }
});

const criticalCount = weekChanges.filter(c => c.criticality === 'CRITICAL').length;
const moderateCount = weekChanges.filter(c => c.criticality === 'MODERATE').length;
const lowCount = weekChanges.filter(c => c.criticality === 'LOW').length;

const byCompetitor = {};
weekChanges.forEach(c => {
  const comp = c.competitor || 'Unknown';
  if (!byCompetitor[comp]) byCompetitor[comp] = { total: 0, critical: 0 };
  byCompetitor[comp].total++;
  if (c.criticality === 'CRITICAL') byCompetitor[comp].critical++;
});

const changesText = weekChanges.length > 0
  ? weekChanges.map(c => `[${c.criticality}] ${c.competitor} — ${c.change_type}: ${c.summary}`).join('\n')
  : 'No se detectaron cambios esta semana.';

const competitorSummary = Object.entries(byCompetitor)
  .map(([comp, data]) => `${comp}: ${data.total} cambio(s), ${data.critical} crítico(s)`)
  .join('\n') || 'Sin actividad';

const weekStart = oneWeekAgo.toISOString().split('T')[0];
const weekEnd = new Date().toISOString().split('T')[0];
const weekNum = Math.ceil(new Date().getDate() / 7);

return [{ json: { totalChanges: weekChanges.length, criticalCount, moderateCount, lowCount, changesText, competitorSummary, weekStart, weekEnd, weekNum } }];

const ctx = $('Build Weekly Context').first().json;
const narrative = ($input.first().json.response || $input.first().json.text || 'Reporte no disponible')
  .replace(/</g, '&lt;').replace(/>/g, '&gt;')
  .replace(/\n/g, '<br>')
  .replace(/\*\*(.*?)\*\*/g, '<strong>$1</strong>');

const criticalBg = ctx.criticalCount > 0 ? '#fef2f2' : '#f0fdf4';
const criticalColor = ctx.criticalCount > 0 ? '#dc2626' : '#16a34a';

const html = `<!DOCTYPE html><html><body style="margin:0;padding:0;background:#f1f5f9;font-family:'Segoe UI',Arial,sans-serif;"><table width="100%" cellpadding="0" cellspacing="0" style="padding:32px 16px;"><tr><td align="center"><table width="620" cellpadding="0" cellspacing="0"><tr><td style="background:linear-gradient(135deg,#0f172a,#1e3a5f,#1e40af);border-radius:16px 16px 0 0;padding:32px;"><p style="margin:0 0 4px;color:rgba(255,255,255,0.6);font-size:11px;text-transform:uppercase;letter-spacing:.1em;">Inteligencia Competitiva Automatizada</p><h1 style="margin:0 0 8px;color:#fff;font-size:22px;">Competitor Intelligence Report</h1><p style="margin:0;color:rgba(255,255,255,0.8);font-size:13px;">Semana ${ctx.weekNum} · ${ctx.weekStart} al ${ctx.weekEnd}</p><p style="margin:4px 0 0;color:rgba(255,255,255,0.4);font-size:11px;">n8n + Ollama llama3.2 · Costo IA: $0</p></td></tr><tr><td style="background:#fff;padding:24px;"><table width="100%" cellpadding="0" cellspacing="0"><tr><td width="25%" style="padding:0 4px 0 0"><div style="background:#eff6ff;border-radius:12px;padding:14px;text-align:center"><div style="font-size:28px;font-weight:800;color:#1e40af">${ctx.totalChanges}</div><div style="font-size:10px;color:#64748b;text-transform:uppercase;margin-top:4px">Cambios</div></div></td><td width="25%" style="padding:0 4px"><div style="background:${criticalBg};border-radius:12px;padding:14px;text-align:center"><div style="font-size:28px;font-weight:800;color:${criticalColor}">${ctx.criticalCount}</div><div style="font-size:10px;color:#64748b;text-transform:uppercase;margin-top:4px">Críticos</div></div></td><td width="25%" style="padding:0 4px"><div style="background:#fefce8;border-radius:12px;padding:14px;text-align:center"><div style="font-size:28px;font-weight:800;color:#d97706">${ctx.moderateCount}</div><div style="font-size:10px;color:#64748b;text-transform:uppercase;margin-top:4px">Moderados</div></div></td><td width="25%" style="padding:0 0 0 4px"><div style="background:#f8fafc;border-radius:12px;padding:14px;text-align:center"><div style="font-size:28px;font-weight:800;color:#64748b">${ctx.lowCount}</div><div style="font-size:10px;color:#64748b;text-transform:uppercase;margin-top:4px">Bajos</div></div></td></tr></table></td></tr><tr><td style="background:#fff;padding:0 24px 24px"><div style="background:#f8fafc;border-left:4px solid #1e40af;border-radius:0 12px 12px 0;padding:20px"><p style="margin:0 0 12px;font-size:11px;font-weight:700;color:#1e40af;text-transform:uppercase;letter-spacing:.08em">Análisis Estratégico — Ollama llama3.2</p><div style="font-size:14px;line-height:1.75;color:#374151">${narrative}</div></div></td></tr><tr><td style="background:#1e293b;border-radius:0 0 16px 16px;padding:16px 24px;text-align:center"><p style="margin:0;color:#94a3b8;font-size:11px">Competitor Monitor AI · Flow 03 — Portfolio Cristian Silva</p></td></tr></table></td></tr></table></body></html>`;

return [{ json: {
  html,
  subject: `Competitor Intelligence — Semana ${ctx.weekNum} · ${ctx.totalChanges} cambios · ${ctx.criticalCount} críticos`
}}];
